import { Link } from "react-router-dom";

const ProfileCard = ({
    profile,
    type,
    quickStats,
    badges = [],
    onClick,
    onDeepDive,
    onToggleCompare,
    onToggleExpand,
    isMobile = false,
    isExpanded = false,
    isCompared = false
}) => {
    const isCreator = type === "creator";
    const summaryPreview = profile.detail.length > 108 ? `${profile.detail.slice(0, 108).trim()}...` : profile.detail;

    return (
        <article
            className={`info-card interactive-card ${isCreator ? "creator-card" : "studio-card"} ${isMobile ? "is-mobile-card" : ""} ${isExpanded ? "is-expanded" : ""}`.trim()}
            role="button"
            tabIndex={0}
            onClick={() => onClick?.(profile, type)}
            onKeyDown={(event) => {
                if (event.key === "Enter" || event.key === " ") {
                    event.preventDefault();
                    onClick?.(profile, type);
                }
            }}
        >
            <div className="info-quick-stats" aria-hidden="true">
                <p>{quickStats?.worksCount || 0} works</p>
                <p>{quickStats?.yearsActive || "N/A"}</p>
            </div>

            {badges.length > 0 && (
                <div className="info-badges" aria-label="Profile badges">
                    {badges.map((badge) => (
                        <span key={`${profile.name}-${badge}`}>{badge}</span>
                    ))}
                </div>
            )}

            <div className="info-header">
                <div>
                    <p className="info-label">
                        {isCreator ? "Creator Name" : "Studio Name"}: {profile.name}
                    </p>
                    <p className="info-meta">{isCreator ? profile.role : profile.meta}</p>
                </div>
                <img
                    src={profile.image}
                    alt={`${profile.name} ${isCreator ? "portrait" : "logo"}`}
                    loading="lazy"
                    decoding="async"
                />
            </div>
            {isCreator && (!isMobile || isExpanded) && <p className="info-sub">{profile.affiliation}</p>}
            <p className={`info-body ${isMobile && !isExpanded ? "is-collapsed" : ""}`}>
                Notable Works: {isMobile && !isExpanded ? summaryPreview : profile.detail}
            </p>
            {(!isMobile || isExpanded) && (
                <div className="related-series">
                    <span>Related series:</span>
                    {profile.related.map((name) => (
                        <Link key={`${profile.name}-${name}`} to="/all-influential-series">
                            {name}
                        </Link>
                    ))}
                </div>
            )}

            <div className="info-actions">
                {isMobile && (
                    <button
                        type="button"
                        className="card-action-btn expand-btn"
                        onClick={(event) => {
                            event.stopPropagation();
                            onToggleExpand?.(profile, type);
                        }}
                    >
                        {isExpanded ? "Collapse" : "Expand"}
                    </button>
                )}
                <button
                    type="button"
                    className="card-action-btn"
                    onClick={(event) => {
                        event.stopPropagation();
                        onDeepDive?.(profile, type);
                    }}
                >
                    Deep Dive
                </button>
                <button
                    type="button"
                    className={`card-action-btn compare-btn ${isCompared ? "is-active" : ""}`}
                    onClick={(event) => {
                        event.stopPropagation();
                        onToggleCompare?.(profile, type);
                    }}
                >
                    {isCompared ? "Selected" : "Compare"}
                </button>
            </div>
        </article>
    );
};

export default ProfileCard;