const SeriesListCard = ({
    series,
    compact = false,
    variant = "default",
    featured = false,
    animated = false,
    interactive = null
}) => {
    if (compact) {
        return (
            <article className="carousel-card tilt-card" id={series.id}>
                <img src={series.image} alt={series.title} loading="lazy" decoding="async" />
                <span>{series.title}</span>
            </article>
        );
    }

    if (variant === "archive") {
        const interactiveProps = interactive
            ? {
                  onClick: interactive.onClick,
                  onKeyDown: interactive.onKeyDown,
                  tabIndex: interactive.tabIndex,
                  role: interactive.role,
                  "aria-label": interactive.ariaLabel
              }
            : {};

        const influenceScore = (8.8 + ((series.title.length * 7) % 13) / 10).toFixed(1);

        if (featured) {
            return (
                <article
                    className={`series-card series-card--featured tilt-card ${animated ? "series-card--animated" : ""}`.trim()}
                    id={series.id}
                    {...interactiveProps}
                >
                    <div className="series-card__media">
                        <img src={series.image} alt={series.title} loading="lazy" decoding="async" />
                        <span className="series-card__title-chip">{series.title}</span>
                    </div>

                    <div className="series-featured-panel" aria-hidden="true">
                        <div className="series-featured-panel__meta">
                            <p>
                                {series.year} <span aria-hidden="true">|</span> {series.studio}
                            </p>
                        </div>

                        <p className="series-featured-panel__synopsis">{series.synopsis}</p>

                        <p className="series-featured-panel__score">Influence Score: {influenceScore}</p>
                    </div>
                </article>
            );
        }

        return (
            <article
                className={`series-card series-card--compact tilt-card ${animated ? "series-card--animated" : ""}`.trim()}
                id={series.id}
                {...interactiveProps}
            >
                <img src={series.image} alt={series.title} loading="lazy" decoding="async" />
                <span className="series-card__title-chip">{series.title}</span>
            </article>
        );
    }

    return (
        <article className="all-series-card" id={series.id}>
            <img src={series.image} alt={series.title} loading="lazy" decoding="async" />
            <div className="all-series-body">
                <h2>{series.title}</h2>
                <p><span>Release:</span> {series.year}</p>
                <p><span>Studio:</span> {series.studio}</p>
                {typeof series.episodes !== "undefined" && <p><span>Episodes:</span> {series.episodes}</p>}
                {series.genre && <p><span>Genre:</span> {series.genre}</p>}
                {series.synopsis && <p>{series.synopsis}</p>}
            </div>
        </article>
    );
};

export default SeriesListCard;
